        private void FrmMain_Load(object sender, EventArgs e)
        {
            try
            {
                AppendLog(LogLevel.Info, "Program Start");
                GlobalValuesAdapter.LoadSettingsFromIni();

                InitPartsStore();

                // Access DB 테이블 구조 확인 및 컬럼 추가 (Final_Angle2 등)
                try
                {
                    ClassDbHelper.EnsureAccessTableStructure(GlobalValuesAdapter.gConString_Record,
                        msg => AppendLog(LogLevel.Info, msg));
                }
                catch (Exception ex)
                {
                    AppendLog(LogLevel.Error, $"[Access] 테이블 구조 확인 실패: {ex.Message}");
                }

                // SQL Server 테이블 구조 확인 및 컬럼 추가 (최초 1회만 실행, 이후는 config.ini 플래그로 건너뜀)
                try
                {
                    ClassDbHelper.EnsureSqlServerTableStructure(GlobalValuesAdapter.gSvrConString_Record,
                        msg => AppendLog(LogLevel.Info, msg));
                }
                catch (Exception ex)
                {
                    AppendLog(LogLevel.Error, $"[SQL] SQL Server 테이블 구조 확인 실패: {ex.Message}");
                }

                // --- 스캐너 ---
                SerialScanner.NewLine = "\r\n";
                SerialScanner.Handshake = Handshake.RequestToSendXOnXOff;
                PortOpen(SerialScanner, GlobalValuesAdapter.ScannerPort, 9600);
                PortOpen(SerialPrinter, GlobalValuesAdapter.PrinterPort, 9600);
                SerialScanner.DataReceived += SerialScanner_DataReceived;

                PortOpen(SerialLvdt, GlobalValuesAdapter.LvdtPort, 115200);
                SerialLvdt.DataReceived += SerialLvdt_DataReceived;

                // --- 전원공급기 ---
                _serialSupply1 = new SerialPort(GlobalValuesAdapter.SupplyPort, 57600, Parity.None, 8, StopBits.One)
                {
                    NewLine = "\n",                // ← ④ LF부터 시작
                    Handshake = Handshake.XOnXOff,
                    ReadTimeout = 2000,
                    WriteTimeout = 2000
                };
                _supply = new SupplyController(_serialSupply1, pollIntervalMs: 50)
                {
                    TargetVolt = 13.5,
                    ResponseTimeoutMs = 1000,
                    Log = AppendLog,
                    Mode = SupplyController.MeasureMode.ModeB
                };
                _supply.Start();

                // --- PLC IO ---
                io = new LsPlcIoFast(GlobalValuesAdapter.PlcPort, 115200)
                {
                    PollDelayMs = 20,
                    ResponseTimeoutMs = 1000,  // 1초 무응답 시 자동 리셋
                    EnableLog = false,
                    VerboseTxRx = false,
                    Log = AppendLog
                };
                io.Open();

                AppendLog("Resist : " + GlobalValuesAdapter.ResistPort);

                _resistMeter = new SerialResistMeter(
                    portName: GlobalValuesAdapter.ResistPort,
                    baudRate: 19200,
                    parity: System.IO.Ports.Parity.None,
                    dataBits: 8,
                    stopBits: System.IO.Ports.StopBits.One,
                    pollIntervalMs: 100,
                    uiContext: SynchronizationContext.Current
                );

                _resistMeter.ResistanceMeasured += OnResistanceMeasured;
                _resistMeter.RawLineReceived += OnRawLine;
                _resistMeter.ErrorOccurred += OnError;

                _resistMeter.Open();
                AppendLog("Resist Open");
                _resistMeter.StartPolling(); // 1초마다 자동 요청
                //_resistMeter.StopPolling();

                // --- ESP32 엔코더 (E40H8-1024, 921600bps) ---
                AppendLog("Encoder : " + GlobalValuesAdapter.AnglePort);
                _esp32Encoder = new ClassEsp32Encoder();
                _esp32Encoder.EncoderName = "Angle";
                _esp32Encoder.SetLogCallback(AppendLog);
                _esp32Encoder.AngleReceived += Esp32Encoder_AngleReceived;
                _esp32Encoder.Connect(GlobalValuesAdapter.AnglePort);
                AppendLog("Encoder Open");

                // --- 타이머 ---
                tmrWork = new System.Windows.Forms.Timer
                {
                    Interval = 100 // 100ms (0.1초)
                };
                tmrWork.Tick += tmrWork_Tick;
                tmrWork.Start();

                tmrDisplay = new System.Windows.Forms.Timer
                {
                    Interval = 100 // 100ms (0.1초)
                };
                tmrDisplay.Tick += tmrDisplay_Tick;
                tmrDisplay.Start();

                // WorkContext 업데이트용 타이머 (tmrWork 사용 시 비활성화)
                // var contextUpdateTimer = new System.Windows.Forms.Timer
                // {
                //     Interval = 100 // 100ms
                // };
                // contextUpdateTimer.Tick += (s, evt) => UpdateWorkContext();
                // contextUpdateTimer.Start();

                // --- 측정 시작 ---
                BeginMeasurement();

                // Phase 2: TestController 초기화 (비활성화 - tmrWork 사용)
                // InitializeTestController();

