        private void StartLogger()
        {
            _logCts = new CancellationTokenSource();
            _logTask = System.Threading.Tasks.Task.Factory.StartNew(
                () => LogWriterLoop(_logCts.Token),
                TaskCreationOptions.LongRunning);
        }
        private void StopLogger()
        {
            if (_logCts == null) return;
            _logCts.Cancel();
            _logQueue.CompleteAdding();
            try { _logTask.Wait(2000); } catch { /* 무시 */ }
            try { _logSw?.Flush(); _logSw?.Dispose(); } catch { }
            _logCts.Dispose();
            _logCts = null;
        }
        private string GetLogPath(DateTime dt)
        {
            string dir = Path.Combine(_logRoot, dt.ToString("yyyy"), dt.ToString("MM"), dt.ToString("dd"));
            Directory.CreateDirectory(dir);
            return Path.Combine(dir, "Log.txt");
        }
        private void EnsureWriter(DateTime now)
        {
            if (_logSw == null || now.Date != _logDate)
            {
                try { _logSw?.Flush(); _logSw?.Dispose(); } catch { }
                _logDate = now.Date;
                _logSw = new StreamWriter(GetLogPath(now), true, new UTF8Encoding(false))
                {
                    AutoFlush = false
                };
            }
        }
        private void LogWriterLoop(CancellationToken ct)
        {
            var lastFlush = DateTime.UtcNow;
            try
            {
                while (!ct.IsCancellationRequested || _logQueue.Count > 0)
                {
                    string line;
                    if (_logQueue.TryTake(out line, 250))
                    {
                        var now = DateTime.Now;
                        EnsureWriter(now);
                        _logSw.WriteLine(line);
                    }

                    // 주기적 flush(0.5초마다)
                    if (_logSw != null && (DateTime.UtcNow - lastFlush).TotalMilliseconds > 500)
                    {
                        _logSw.Flush();
                        lastFlush = DateTime.UtcNow;
                    }
                }
            }
            catch (Exception ex)
            {
                System.Diagnostics.Debug.WriteLine("[LOG LOOP FAIL] " + ex);
            }
            finally
            {
                try { _logSw?.Flush(); _logSw?.Dispose(); } catch { }
            }
        }
        // Phase 4: 로깅 개선 - 기존 메서드 유지 (호환성)
        public void AppendLog(string msg)
        {
            if (_logPaused) return;
            AppendLog(LogLevel.Info, msg);
        }

        // Phase 4: 로그 레벨을 지정할 수 있는 오버로드 추가
        public void AppendLog(LogLevel level, string msg)
        {
            string line = $"[{DateTime.Now:HH:mm:ss}][{wStep}][{level.ToString().ToUpper()}] {msg}";
            _logQueue.Add(line);  // ← 매우 빠름 (비동기)

            // UI는 기존처럼 BeginInvoke로 가볍게
            if (textBox1.IsHandleCreated)
            {
                if (textBox1.InvokeRequired)
                    textBox1.BeginInvoke(new Action(() => textBox1.AppendWithTrim(line)));
                else
                    textBox1.AppendWithTrim(line);
            }
        }

        // Phase 4: 예외 포함 로깅
        public void AppendLog(LogLevel level, string msg, Exception ex)
        {
            string line = $"[{DateTime.Now:HH:mm:ss}][{wStep}][{level.ToString().ToUpper()}] {msg}";
            if (ex != null)
            {
                line += $": {ex.Message}";
                if (ex.StackTrace != null)
                {
                    line += Environment.NewLine + $"StackTrace: {ex.StackTrace}";
                }
            }
            _logQueue.Add(line);

            // UI 업데이트
            if (textBox1.IsHandleCreated)
            {
                if (textBox1.InvokeRequired)
                    textBox1.BeginInvoke(new Action(() => textBox1.AppendWithTrim(line)));
                else
                    textBox1.AppendWithTrim(line);
            }
        }

