            SpecSpeed[3].Text = $"{Spec.SpeedMin} - {Spec.SpeedMax} °/s";

            Spec_SwitchAngle.Text = $"{Spec.SwitchAngleMin} - {Spec.SwitchAngleMax} °";
            Spec_Angle.Text = $"{Spec.AngleMin} - {Spec.AngleMax} °";
            Spec_CW_Resist.Text = $"{Spec.ResistMin} - {Spec.ResistMax} Ω";
            Spec_CCW_Resist.Text = $"{Spec.ResistMin} - {Spec.ResistMax} Ω";

            FlagUseWeight = Spec.UseWeight;

            BasicResistMax = Spec.ResistMax;
            BasicResistMin = Spec.ResistMin;
            BasicAngleMax = Spec.AngleMax;
            BasicAngleMin = Spec.AngleMin;

            BasicSwitchAngleMax = Spec.SwitchAngleMax;
            BasicSwitchAngleMin = Spec.SwitchAngleMin;

            BaicTargetSwichVolt = Spec.SwitchAngleVolt;

            // 180도 각도 스펙
            BasicAngle2Min = Spec.Angle2Min;
            BasicAngle2Max = Spec.Angle2Max;
            Spec_Angle2.Text = $"{Spec.Angle2Min} - {Spec.Angle2Max} °";

            // 버니싱 횟수
            BasicBurnishCount = Spec.BurnishCount;

        }
        private void OnDbAvailable(double[] db)
        {
            // 채널별 dB 값 출력
            string msg = $"dB 값: {string.Join(", ", db)}";
            AppendLog(msg);

            // 예: 첫 번째 채널의 dB 값을 라벨에 표시
            if (db.Length > 0)
            {
                this.BeginInvoke(new Action(() =>
                {
                    srcLbNoise.Text = $"{db[0]:F2} dB"; // 라벨에 표시
                }));
            }
        }

        private double switchAngleStart = 0;
        private double switchAngleEnd = 0;

        // 각도 변화량 그래프용 변수
        private System.Diagnostics.Stopwatch _angleGraphSw = new System.Diagnostics.Stopwatch();
        private double _angleGraphStartAngle = 0;
        private double _angleGraphFirstNonZeroTime = 0; // 첫 번째 0이 아닌 값이 나타나는 시점
        private List<Sample> _angleGraphSamples = new List<Sample>(); // 각도 변화량 샘플 수집
        private double _switchActivationTime = 0; // 스위치 작동 시점 (통전 검출 시점)

        private void tmrDisplay_Tick(object sender, EventArgs e)
        {
            srcLbVolt.Text = $"{_supply.ValueVolt.ToString()}";
            srcLbCurr.Text = $"{_supply.ValueCurr.ToString()}";
            srcLbNoise.Text = _monitor.Value.ToString();
        }

        private int ResetStep = 0;
        private DateTime _resetOut31OnTime;
        private DateTime _gripDelayTime; // 각도그립 실린더 딜레이용

        private void tmrWork_Tick(object sender, EventArgs e)
        {
            srcStep.Text = $"State[{wStep.ToString()}] ResetStep[{ResetStep}]";

            // io가 null이면 처리 안 함
            if (io == null) return;

            // 비상정지 체크 (Input 2가 false일 때 = 비상정지 버튼 B접)
            if (!io.GetInput(2))
            {
                // 모든 IO 출력 OFF
                for (int i = 0; i <= 29; i++)
                {
                    io.Do_Off_Force(i);
                }
                io.Commit();

                wStep = 2000;
                if (PanelAlarm != null && LbAlarm != null)
                {
                    PanelAlarm.Visible = true;
                    LbAlarm.Text = "비상정지 눌림! 해제후 리셋";
                }
                AppendLog("[비상정지] 비상정지 버튼 눌림 - 모든 출력 OFF");
                return;
            }

            // 비상정지 해제 대기 (wStep == 2000)
            if (wStep == 2000)
            {
                // 비상정지 해제 확인 (Input 2가 true일 때)
                if (io.GetInput(1) && io.GetInput(2))
                {
                    AppendLog("[비상정지] 비상정지 해제됨 - 리셋");
                    // 비상정지 해제 시 전압을 13.5V로 설정
                    if (_supply != null)
                    {
                        _supply.TargetVolt = 13.5;
                        AppendLog($"[비상정지 해제] 전압을 13.5V로 설정");
                    }
                    wStep = 0;
                    ResetStep = 0;
                    // 해제 후에도 wStep = 2000 유지 (리셋 필요)
                }
                return; // 비상정지 상태에서는 다른 작업 진행 안 함
            }

            // ResetStep 처리
            {
                // 리셋 스위치 감지 (Input 1)
                if (io.GetInput(1) && ResetStep == 0)
                {
                    // 모든 출력 OFF
                    for (int i = 0; i <= 29; i++)
                    {
                        io.Do_Off_Force(i);
                    }
                    io.Commit();
                    PanelAlarm.Visible = false;
                    AppendLog("[0]리셋 시작");
                    ResetStep = 1;
                    return;
                }

                switch (ResetStep)
                {
                    case 1:
                        AppendLog("[1]웨이트 상승/게이지 후진");
                        io.Do_On_Force(5);  // 웨이트 상승
                        io.Do_On_Force(11); // 게이지 후진
                        io.Do_On_Force(13); // 웨이트 고정 1
                        io.Do_On_Force(15); // 웨이트 고정 2                        
                        io.Commit();
                        ResetStep = 2;
                        break;

                    case 2:
                        if (io.GetInput(8) && io.GetInput(14) && io.GetInput(15) && io.GetInput(18))
                        {
                            AppendLog("[2]센서받음");
                            io.Do_Off_Force(5);
                            io.Do_Off_Force(11);
                            io.Do_Off_Force(13);
                            io.Do_Off_Force(15);
                            io.Do_On_Force(3); // 원위치 이동
                            io.Commit();
                            ResetStep = 3;
                        }
                        break;

                    case 3:
                        if (io.GetInput(6)) // 원위치 센서
                        {
                            AppendLog("[3]언클램프");
                            io.Do_Off_Force(3);
                            io.Do_On_Force(1); // 언클램프
                            io.Commit();
                            ResetStep = 4;
                        }
                        break;

                    case 4:
                        if (io.GetInput(4)) // 언클램프 센서
                        {
                            AppendLog($"[ResetStep {ResetStep}] 언클램프 센서 확인됨");
                            io.Do_Off_Force(1);
                            io.Do_On_Force(29); // OUT29 ON
                            io.Commit();
                            AppendLog("[ResetStep 41] OUT29 ON");
                            ResetStep = 41;
                        }
                        break;

                    case 41: // IN10 확인 후 OUT29 OFF, OUT31 ON
                        if (io.GetInput(10))
                        {
                            AppendLog("[ResetStep 41] IN10 확인 - OUT29 OFF, OUT31 ON");
                            io.Do_Off_Force(29);
                            io.Do_On_Force(31);
                            io.Commit();
                            _resetOut31OnTime = DateTime.Now;
                            ResetStep = 42;
                        }
                        break;

                    case 42: // OUT31 1초 후 OFF
                        if ((DateTime.Now - _resetOut31OnTime).TotalSeconds >= 1.0)
                        {
                            AppendLog("[ResetStep 42] 1초 경과 - OUT31 OFF");
                            io.Do_Off_Force(31);
                            io.Commit();
                            ResetStep = 5;
                        }
                        break;

                    case 5:
                        if (!io.GetInput(1)) // 리셋 스위치 해제
                        {
                            AppendLog($"[ResetStep {ResetStep}] 리셋 스위치 해제 확인됨");
                            io.Do_Off_Force(1);
                            io.Commit();
                            ResetStep = 6;
                        }
                        break;

                    case 6:
                        AppendLog("리셋 완료");
                        // 리셋 시 전압을 13.5V로 설정
                        if (_supply != null)
                        {
                            _supply.TargetVolt = 13.5;
                            AppendLog($"[리셋] 전압을 13.5V로 설정");
                        }
                        ResetStep = 0;
                        wStep = 0;
                        break;
                }
            }

            // ResetStep이 0일 때만 메인 작업 진행
            if (ResetStep != 0) return;

            // 메인 작업 상태머신 (wStep 기반)
            switch (wStep)
            {
                case 0: // 스캔 대기
                    // 스캔 완료는 SerialScanner_DataReceived에서 처리
                    break;

                case 1: // 스캔 완료
                    AppendLog($"[wStep {wStep}] 스캔 완료 - 모든 출력 OFF");
                    // 모든 출력 OFF
                    for (int i = 0; i <= 29; i++)
                    {
                        io.Do_Off_Force(i);
                    }
                    io.Commit();
                    ShowBasic();
                    wStep = 2;
                    break;

                case 2: // 시작 버튼 대기
                    if (io.GetInput(0)) // 시작 버튼
                    {
                        AppendLog($"[wStep {wStep}] 시작 버튼 감지 - 검사 시작");
                        wStep = 3;
                    }
                    break;

                case 3: // 클램프
                    AppendLog($"[wStep {wStep}] 클램프 시작");
                    io.Do_On_Force(0); // 클램프
                    io.Commit();
                    wStep = 4;
                    break;

                case 4: // 클램프 센서 확인
                    if (io.GetInput(3) && !io.GetInput(0)) // 클램프 센서 && 시작 버튼 해제
                    {
                        AppendLog($"[wStep {wStep}] 클램프 센서 확인 완료");
                        io.Do_Off_Force(0);
                        io.Commit();
                        // 버니싱 횟수 확인 후 분기
                        if (BasicBurnishCount > 0)
                        {
                            wStep = 4.005; // 버니싱 안내로 이동
                        }
                        else
                        {
                            wStep = 4.01;  // 버니싱 스킵, 각도기 거치 안내로
                        }
                    }
                    break;

                // ===== 버니싱 스텝 (4.005 ~ 4.0095) =====
                case 4.005: // 버니싱 안내 - 버튼 대기
                    AppendLog($"[wStep {wStep}] 버니싱 안내 표시 (횟수: {BasicBurnishCount})");
                    _burnishTotal = BasicBurnishCount;
                    _burnishCurrent = 0;
                    if (PanelAlarm != null && LbAlarm != null)
                    {
                        PanelAlarm.Visible = true;
                        LbAlarm.Text = "버튼을 눌러 버니싱 동작";
                    }
                    wStep = 4.006;
                    break;

                case 4.006: // 버니싱 버튼 대기
                    if (io.GetInput(0)) // 시작 버튼
                    {
                        AppendLog($"[wStep {wStep}] 버니싱 시작 버튼 눌림");
                        if (PanelAlarm != null)
                        {
                            PanelAlarm.Visible = false;
                        }
                        // 전압 설정
                        if (_supply != null)
                        {
                            _supply.TargetVolt = 13.5;
                        }
                        _burnishCurrent = 1;
                        wStep = 4.007;
                    }
                    break;

                case 4.007: // 버니싱 CW 동작 시작
                    AppendLog($"[wStep {wStep}] 버니싱 {_burnishCurrent}/{_burnishTotal}회 CW 동작 시작");
                    if (PanelAlarm != null && LbAlarm != null)
                    {
                        PanelAlarm.Visible = true;
                        LbAlarm.Text = $"버니싱 {_burnishCurrent}/{_burnishTotal}회 CW 진행중";
                    }
                    io.Do_On_Force(24); // CW 동작
                    io.Commit();
                    wStep = 4.0071;
                    break;

                case 4.0071: // 버니싱 CW 정지 대기 (전류 >= 9A)
                    if (_supply != null && _supply.ValueCurr >= 9)
                    {
                        AppendLog($"[wStep {wStep}] 버니싱 CW 정지 (전류: {_supply.ValueCurr:F2}A)");
                        io.Do_Off_Force(24);
                        io.Commit();
                        wStep = 4.008;
                    }
                    break;

                case 4.008: // 버니싱 CCW 동작 시작
                    AppendLog($"[wStep {wStep}] 버니싱 {_burnishCurrent}/{_burnishTotal}회 CCW 동작 시작");
                    if (PanelAlarm != null && LbAlarm != null)
                    {
                        LbAlarm.Text = $"버니싱 {_burnishCurrent}/{_burnishTotal}회 CCW 진행중";
                    }
                    io.Do_On_Force(25); // CCW 동작
                    io.Commit();
                    wStep = 4.0081;
                    break;

                case 4.0081: // 버니싱 CCW 정지 대기 (전류 >= 9A)
                    if (_supply != null && _supply.ValueCurr >= 9)
                    {
                        AppendLog($"[wStep {wStep}] 버니싱 CCW 정지 (전류: {_supply.ValueCurr:F2}A)");
                        io.Do_Off_Force(25);
                        io.Commit();
                        wStep = 4.009;
                    }
                    break;

                case 4.009: // 버니싱 싸이클 완료 체크
                    AppendLog($"[wStep {wStep}] 버니싱 {_burnishCurrent}/{_burnishTotal}회 완료");
                    if (_burnishCurrent < _burnishTotal)
                    {
                        // 다음 싸이클
                        _burnishCurrent++;
                        wStep = 4.007;
                    }
                    else
                    {
                        // 버니싱 완료 → 각도기 거치 안내로
                        AppendLog($"[wStep {wStep}] 버니싱 전체 완료 ({_burnishTotal}회)");
                        if (PanelAlarm != null)
                        {
                            PanelAlarm.Visible = false;
                        }
                        wStep = 4.01;
                    }
                    break;

                case 4.01: // 각도그립 전진 (OUT30 ON)
                    AppendLog($"[wStep {wStep}] 각도그립 전진 - OUT30 ON");
                    io.Do_On_Force(30);
                    io.Commit();
                    wStep = 4.011;
                    break;

                case 4.011: // 각도그립 위치 확인 (IN09)
                    if (io.GetInput(9))
                    {
                        AppendLog($"[wStep {wStep}] IN09 확인 - OUT30 OFF, OUT31 ON (후진)");
                        io.Do_Off_Force(30);
                        io.Do_On_Force(31);
                        io.Commit();
                        _gripDelayTime = DateTime.Now;
                        wStep = 4.012;
                    }
                    break;

                case 4.012: // 0.5초 딜레이 후 OUT31 OFF, OUT28 ON (상승)
                    if ((DateTime.Now - _gripDelayTime).TotalSeconds >= 0.5)
                    {
                        AppendLog($"[wStep {wStep}] 0.5초 경과 - OUT31 OFF, OUT28 ON (각도그립 상승)");
                        io.Do_Off_Force(31);
                        io.Do_On_Force(28);
                        io.Commit();
                        wStep = 4.013;
                    }
                    break;

                case 4.013: // 장비 부착 확인 (IN11)
                    if (io.GetInput(11))
                    {
                        AppendLog($"[wStep {wStep}] IN11 확인 - OUT28 OFF");
                        io.Do_Off_Force(28);
                        io.Commit();
                        _esp32Encoder?.SendZero(); // 각도 제로 세팅
                        AppendLog($"[wStep {wStep}] ESP32 ZERO 명령 전송");
                        _gripDelayTime = DateTime.Now;
                        wStep = 4.014;
                    }
                    break;

                case 4.014: // ESP32 ZERO 확인 후 각도기 0 세팅
                    if (Math.Abs(ValueAngleZ) < 1.0) // 제로 확인 (±1° 이내)
                    {
                        switchAngleStart = ValueAngleZ;
                        AppendLog($"[wStep {wStep}] 각도기 0 세팅 완료: {switchAngleStart:F3}°");
                        io.Do_On_Force(20); // 통전 검사 릴레이 ON
                        io.Commit();
                        AppendLog($"[wStep {wStep}] OUT20 ON - 통전 검사 릴레이 ON");
                        wStep = 4.05;
                    }
                    else if ((DateTime.Now - _gripDelayTime).TotalSeconds >= 3.0) // 3초 타임아웃
                    {
                        AppendLog($"[wStep {wStep}] 경고: ZERO 타임아웃 - 현재 각도 {ValueAngleZ:F3}° 로 진행");
                        switchAngleStart = ValueAngleZ;
                        io.Do_On_Force(20);
                        io.Commit();
                        wStep = 4.05;
                    }
                    break;

                case 4.05: // 스위치 작동 전압 확인
                    if (_supply != null)
                    {
                        _supply.Mode = SupplyController.MeasureMode.ModeB;
                        _supply.TargetVolt = BaicTargetSwichVolt;
                        AppendLog($"[wStep {wStep}] 스위치 작동 전압 확인 중... (목표: {BaicTargetSwichVolt}V, 현재: {_supply.ValueVolt:F2}V)");

                        if (_supply.ValueVolt >= BaicTargetSwichVolt - 0.1 && _supply.ValueVolt <= BaicTargetSwichVolt + 0.1)
                        {
                            AppendLog($"[wStep {wStep}] 스위치 작동 전압 확인 완료 = {BaicTargetSwichVolt}V");
                            wStep = 4.06;
                        }
                    }
                    break;

                case 4.06: // CW 동작 시작
                    AppendLog($"[wStep {wStep}] CW 동작 시작");

                    // 각도 변화량 그래프 초기화 및 시작값 저장
                    ClassZedGraph.InitGraph(GraphAngle, "SWITCH ANGLE", "Angle (°)", 0, 3, curveColor: Color.DarkGreen, lineWidth: 2.5f);
                    _angleGraphStartAngle = ValueAngleZ;
                    _angleGraphFirstNonZeroTime = 0;
                    _angleGraphSamples.Clear(); // 샘플 초기화
                    _switchActivationTime = 0; // 스위치 작동 시점 초기화
                    _angleGraphSw.Restart();

                    io.Do_On_Force(24); // CW 동작
                    io.Commit();
                    wStep = 4.07;
                    break;

                case 4.07: // 통전 검출 대기
                    // 각도 변화량 그래프 그리기
                    {
                        double elapsed = _angleGraphSw.Elapsed.TotalSeconds;

                        // 옵션 1: 실제 각도 측정값 (기본값, 테스트 권장)
                        //double graphValue = ValueAngleZ;

                        // [임시] CW 시 측정값이 +로 나옴 → 부호 반전 후 abs 처리 (BSS138 24V 신호 왜곡 임시조치)
                        double graphValue = Math.Abs(-(ValueAngleZ - switchAngleStart));

                        // 옵션 3: 각도 변화량 (현재 방식)
                        // double angleDelta = Math.Abs(ValueAngleZ - _angleGraphStartAngle);
                        // double graphValue = angleDelta;

                        // 각도 샘플 수집 (최대값까지 그리기 위해)
                        _angleGraphSamples.Add(new Sample { t = elapsed, v = graphValue });

                        // 첫 번째 0이 아닌 값이 나타나는 시점 추적
                        if (_angleGraphFirstNonZeroTime == 0 && graphValue > 0.01)
                        {
                            _angleGraphFirstNonZeroTime = elapsed;
                            AppendLog($"[그래프] 첫 번째 0이 아닌 값 감지: {graphValue:F3}° (시간: {elapsed:F3}초)");
                        }

                        // 0이 아닌 값이 나타난 후에만 그래프에 표시
                        if (_angleGraphFirstNonZeroTime > 0)
                        {
                            // X축 오프셋 적용 (첫 번째 0이 아닌 값 시점을 0으로 설정)
                            double adjustedTime = elapsed - _angleGraphFirstNonZeroTime;
                            ClassZedGraph.DrawGraph(GraphAngle, graphValue, adjustedTime);
                        }
                    }

                    // 통전 검출 시 스위치 작동 시점 저장
                    if (io != null && io.GetInput(22)) // 통전 검출 (IN22)
                    {
                        if (_switchActivationTime == 0)
                        {
                            _switchActivationTime = _angleGraphSw.Elapsed.TotalSeconds;
                            switchAngleEnd = ValueAngleZ; // IN22 순간 각도 캡처
                            AppendLog($"[그래프] 스위치 작동 시점 저장: {_switchActivationTime:F3}초, 각도: {switchAngleEnd:F3}°");
                        }

                        // _angleGraphSw는 Stop()하지 않음 (case 4.08에서 계속 샘플 수집하기 위해)
                        AppendLog($"[wStep {wStep}] 통전 검출됨 - CW 동작 정지");
                        io.Do_Off_Force(24);
                        io.Commit();
                        sw.Restart();
                        wStep = 4.08;
                    }
                    break;

                case 4.08: // 종료 각도 저장 및 계산
                    // 1초 대기하는 동안 계속 샘플 수집
                    if (sw.Elapsed.TotalSeconds < 1.0)
                    {
                        // 각도 샘플 계속 수집 (통전 검출 후에도 각도 변화 수집)
                        double elapsed = _angleGraphSw.Elapsed.TotalSeconds;
                        // [임시] BSS138 24V 신호 왜곡 임시조치 - 부호 반전 + abs
                        double graphValue = Math.Abs(-(ValueAngleZ - switchAngleStart));
                        _angleGraphSamples.Add(new Sample { t = elapsed, v = graphValue });
                    }
                    else if (sw.Elapsed.TotalSeconds >= 1.0)
                    {
                        // switchAngleEnd는 IN22 감지 순간(case 4.07)에 이미 캡처됨
                        // [임시] BSS138 24V 신호 왜곡 임시조치 - 부호 반전 + abs
                        double switchAngle = Math.Abs(-(switchAngleEnd - switchAngleStart));
                        // Val_SwitchAngle은 교점의 Y값으로 설정 (교점 계산 후 업데이트됨)
                        // 임시로 switchAngle 설정 (교점 계산 실패 시 사용)
                        double finalSwitchAngle = switchAngle;

                        // 최종 각도값을 샘플에 추가 (switchAngleEnd 저장 시점)
                        double finalElapsed = _angleGraphSw.Elapsed.TotalSeconds;
                        double finalGraphValue = switchAngle;
                        _angleGraphSamples.Add(new Sample { t = finalElapsed, v = finalGraphValue });

                        // 이제 _angleGraphSw를 Stop() (더 이상 샘플 수집 불필요)
                        _angleGraphSw.Stop();

                        // 각도 변화량 최대값 찾기
                        double maxAngleValue = 0;
                        foreach (var sample in _angleGraphSamples)
                        {
                            if (sample.v > maxAngleValue)
                                maxAngleValue = sample.v;
                        }

                        // 그래프를 최대값까지 다시 그리기
                        if (maxAngleValue > 0 && _angleGraphFirstNonZeroTime > 0)
                        {
                            // X축 시작점 0, Y축 범위 0~3 고정
                            ClassZedGraph.InitGraph(GraphAngle, "SWITCH ANGLE", "Angle (°)", 0, 3, curveColor: Color.DarkGreen, lineWidth: 2.5f);

                            // 각도 변화량 그래프 그리기 (최대값까지) - 배치로 포인트 추가
                            var pane = GraphAngle.GraphPane;

                            if (pane.CurveList.Count > 0)
                            {
                                var curve = pane.CurveList[0];
                                var pts = curve.Points as ZedGraph.IPointListEdit;

                                if (pts != null)
                                {
                                    double maxX = 0;

                                    foreach (var sample in _angleGraphSamples)
                                    {
                                        double adjustedTime = sample.t - _angleGraphFirstNonZeroTime;
                                        if (adjustedTime >= 0)
                                        {
                                            pts.Add(adjustedTime, sample.v);
                                            if (adjustedTime > maxX)
                                                maxX = adjustedTime;
                                        }
                                    }

                                    // X축 범위 설정 (최소 1.0초까지 표시)
                                    pane.XAxis.Scale.Min = 0;
                                    double xMax = Math.Max(maxX, 1.0);
                                    pane.XAxis.Scale.Max = xMax;

                                    // X축 시간 레이블이 표시되도록 MajorStep과 MinorStep 조정
                                    if (xMax <= 2.0)
                                    {
                                        pane.XAxis.Scale.MajorStep = 0.5;
                                        pane.XAxis.Scale.MinorStep = 0.1;
                                    }
                                    else if (xMax <= 5.0)
                                    {
                                        pane.XAxis.Scale.MajorStep = 1.0;
                                        pane.XAxis.Scale.MinorStep = 0.5;
                                    }
                                    else if (xMax <= 10.0)
                                    {
                                        pane.XAxis.Scale.MajorStep = 2.0;
                                        pane.XAxis.Scale.MinorStep = 1.0;
                                    }
                                    else
                                    {
                                        pane.XAxis.Scale.MajorStep = 5.0;
                                        pane.XAxis.Scale.MinorStep = 1.0;
                                    }

                                    GraphAngle.AxisChange();
                                    GraphAngle.Invalidate();
                                }
                            }

                            // 스위치 작동 시점에 수직 점선 추가 (빨간색)
                            if (_switchActivationTime > 0 && _angleGraphFirstNonZeroTime > 0)
                            {
                                double adjustedActivationTime = _switchActivationTime - _angleGraphFirstNonZeroTime;

                                if (adjustedActivationTime >= 0)
                                {
                                    ClassZedGraph.AddGuideLines(
                                        GraphAngle,
                                        null, // Y 기준선 없음
                                        new[] { adjustedActivationTime }, // X 기준선 (수직 점선)
                                        null,
                                        Color.Red, // 빨간색 점선
                                        2.0f,
                                        DashStyle.Dash);
                                }
                            }

                            // 스위치 작동 시점의 각도값 찾기 및 Val_SwitchAngle 설정
                            if (_switchActivationTime > 0)
                            {
                                double switchActivationAngle = GetAngleAtTime(_angleGraphSamples, _switchActivationTime);
                                if (switchActivationAngle > 0)
                                {
                                    finalSwitchAngle = switchActivationAngle;
                                    Val_SwitchAngle.Text = switchActivationAngle.ToString("F2");
                                    AppendLog($"[그래프] 스위치 작동 시점 각도: {switchActivationAngle:F2}° (시간: {_switchActivationTime:F3}초)");
                                }
                                else
                                {
                                    // 샘플에서 찾지 못한 경우 기존 switchAngle 사용
                                    finalSwitchAngle = switchAngle;
                                    Val_SwitchAngle.Text = switchAngle.ToString("F2");
                                }
                            }
                            else
                            {
                                // 스위치 작동 시점이 없는 경우 기존 switchAngle 사용
                                finalSwitchAngle = switchAngle;
                                Val_SwitchAngle.Text = switchAngle.ToString("F2");
                            }
                        }

                        // 판정 (교점 각도값 사용)
                        bool switchAngleOk = finalSwitchAngle >= BasicSwitchAngleMin && finalSwitchAngle <= BasicSwitchAngleMax;
                        if (switchAngleOk)
                        {
                            Dec_SwitchAngle.Text = "OK";
                            Dec_SwitchAngle.BackColor = Color.Blue;
                            AppendLog($"[wStep {wStep}] 스위치 각도 측정 완료: {switchAngle:F2}° (OK, 범위: {BasicSwitchAngleMin}~{BasicSwitchAngleMax}°)");
                        }
                        else
                        {
                            Dec_SwitchAngle.Text = "NG";
                            Dec_SwitchAngle.BackColor = Color.Red;
                            AppendLog($"[wStep {wStep}] 스위치 각도 측정 완료: {switchAngle:F2}° (NG, 범위: {BasicSwitchAngleMin}~{BasicSwitchAngleMax}°)");
                        }

                        // 통전 검사 릴레이 OFF
                        io.Do_Off_Force(20);
                        io.Commit();
                        AppendLog($"[wStep {wStep}] OUT20 OFF - 통전 검사 릴레이 OFF");

                        io.Do_On_Force(2); // 검사위치 이동
                        io.Commit();
                        wStep = 5;
                    }
                    break;

                case 5: // 검사위치 센서 대기
                    if (io.GetInput(5)) // 검사위치 센서
                    {
                        AppendLog($"[wStep {wStep}] 검사위치 센서 확인됨");
                        io.Do_Off_Force(2);
                        io.Commit();
                        wStep = 7;
                    }
                    break;

                case 7: // 검사 전압 확인
                    if (_supply != null)
                    {
                        _supply.Mode = SupplyController.MeasureMode.ModeB;
                        _supply.TargetVolt = 13.5;
                        AppendLog($"[wStep {wStep}] 검사 전압 확인 중... (목표: 13.5V, 현재: {_supply.ValueVolt:F2}V)");

                        if (_supply.ValueVolt >= 13.4 && _supply.ValueVolt <= 13.6)
                        {
                            _supply.Mode = SupplyController.MeasureMode.ModeA;
                            AppendLog($"[wStep {wStep}] 검사 전압 확인 완료 = 13.5V");
                            wStep = 8;
                        }
                    }
                    break;

                case 8: // CCW 동작 시작
                    AppendLog($"[wStep {wStep}] CCW 동작 시작");
                    io.Do_On_Force(25); // CCW 동작
                    io.Commit();
                    wStep = 9;
                    break;

                case 9: // CCW 동작 정지
                    if (_supply != null && _supply.ValueCurr >= 9)
                    {
                        AppendLog($"[wStep {wStep}] CCW 동작 정지 (전류: {_supply.ValueCurr:F2}A)");
                        io.Do_Off_Force(25);
                        io.Commit();
                        wStep = 10;
                    }
                    break;

                case 10: // 웨이트 사용 여부 확인
                    if (FlagUseWeight)
                    {
                        AppendLog($"[wStep {wStep}] 웨이트 사용 - 웨이트 하강으로 이동");
                        wStep = 100;
                    }
                    else
                    {
                        AppendLog($"[wStep {wStep}] 웨이트 미사용 - 테스트 시작으로 이동");
                        wStep = 200;
                    }
                    break;

                case 100: // 웨이트 하강
                    AppendLog($"[wStep {wStep}] 웨이트 하강 시작");
                    io.Do_On_Force(4); // 웨이트 하강
                    io.Commit();
                    wStep = 101;
                    break;

                case 101: // 웨이트 하강 센서
                    if (io.GetInput(7))
                    {
                        AppendLog($"[wStep {wStep}] 웨이트 하강 센서 확인됨 - 웨이트 고정 후진 시작");
                        io.Do_Off_Force(4);
                        io.Do_On_Force(13); // 웨이트 고정 1
                        io.Do_On_Force(15); // 웨이트 고정 2
                        io.Commit();
                        wStep = 102;
                    }
                    break;

                case 102: // 웨이트 고정 후진
                    if (io.GetInput(15) && io.GetInput(18))
                    {
                        AppendLog($"[wStep {wStep}] 웨이트 고정 후진 센서 확인됨");
                        io.Do_Off_Force(13);
                        io.Do_Off_Force(15);
                        io.Commit();
                        wStep = 200;
                    }
                    break;

                case 102.1: // 너트 조립 안내
                    AppendLog($"[wStep {wStep}] 너트 조립 안내 표시");
                    if (PanelAlarm != null && LbAlarm != null)
                    {
                        PanelAlarm.Visible = true;
                        LbAlarm.Text = "너트 조립 후 버튼을 눌러주세요.";
                    }
                    wStep = 103;
                    break;

                case 103: // 너트 조립 확인
                    if (io.GetInput(0)) // 시작 버튼
                    {
                        AppendLog($"[wStep {wStep}] 너트 조립 확인됨 - 테스트 시작으로 이동");
                        if (PanelAlarm != null)
                        {
                            PanelAlarm.Visible = false;
                        }
                        wStep = 200;
                    }
                    break;

                case 200: // 테스트 시작
                    AppendLog($"[wStep {wStep}] 테스트 시작 준비");
                    // 테스트 데이터 초기화
                    _testDataRecorder.Clear();
                    sw.Restart();
                    StartTime = DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss");
                    AppendLog($"[wStep {wStep}] 테스트 시작 시간: {StartTime}");
                    wStep = 201;
                    break;

                case 201: // CW 테스트 시작
                    AppendLog($"[wStep {wStep}] CW 테스트 시작");
                    // tmrWork는 계속 실행 (비상정지 체크를 위해)
                    wStep = 201.1;
                    NoiseCurrentTest(24, Graph[0], Graph[1], Graph[4],
                        ValStartUp[0], ValOperating[0], ValStartUp[1], ValOperating[1],
                        ValSpeed[0], Val_CW_Resist_Min, Val_CW_Resist_Max,
                        DecStartUp[0], DecOperating[0], DecStartUp[1], DecOperating[1],
                        DecSpeed[0], Dec_CW_Resist, gTestID);
                    // NoiseCurrentTest 내부에서 wStep = 202로 변경됨 (비상정지 시 wStep = 2000)
                    break;

                // ===== 180도 검사 (case 201.5 ~ 201.9) =====
                case 201.5: // 180도 검사 시작 - 게이지 전진
                    AppendLog($"[wStep {wStep}] 180도 검사 시작 - 게이지 전진");
                    io.Do_On_Force(10); // 게이지 전진
                    io.Commit();
                    wStep = 201.6;
                    break;

                case 201.6: // 게이지 전진 센서 확인
                    if (io.GetInput(13)) // 게이지 전진 센서
                    {
                        AppendLog($"[wStep {wStep}] 게이지 전진 센서 확인됨 - 2초 대기 시작");
                        io.Do_Off_Force(10);
                        io.Commit();
                        sw.Restart();
                        wStep = 201.7;
                    }
                    break;

                case 201.7: // 2초 대기
                    if (sw.Elapsed.TotalSeconds >= 2.0)
                    {
                        AppendLog($"[wStep {wStep}] 2초 대기 완료 - 180도 각도 측정 시작");
                        wStep = 201.8;
                    }
                    break;

                case 201.8: // 180도 각도 측정 및 판정
                    double angle2 = ComputeTiltDeg(ValueLvdt1, ValueLvdt2, 160.0);
                    Val_Angle2.Text = angle2.ToString("F2");

                    // 180도 각도 판정
                    bool angle2Ok = angle2 >= BasicAngle2Min && angle2 <= BasicAngle2Max;
                    if (angle2Ok)
                    {
                        Dec_Angle2.Text = "OK";
                        Dec_Angle2.BackColor = Color.Blue;
                        AppendLog($"[wStep {wStep}] 180도 각도 측정: {angle2:F2}° (OK, 범위: {BasicAngle2Min}~{BasicAngle2Max}°)");
                    }
                    else
                    {
                        Dec_Angle2.Text = "NG";
                        Dec_Angle2.BackColor = Color.Red;
                        AppendLog($"[wStep {wStep}] 180도 각도 측정: {angle2:F2}° (NG, 범위: {BasicAngle2Min}~{BasicAngle2Max}°)");
                    }

                    wStep = 201.85;
                    break;

                case 201.85: // 게이지 후진
                    AppendLog($"[wStep {wStep}] 180도 검사 완료 - 게이지 후진");
                    io.Do_On_Force(11); // 게이지 후진
                    io.Commit();
                    wStep = 201.9;
                    break;

                case 201.9: // 게이지 후진 센서 확인 후 CCW 테스트로
                    if (io.GetInput(14)) // 게이지 후진 센서
                    {
                        AppendLog($"[wStep {wStep}] 게이지 후진 센서 확인됨 - CCW 테스트로 이동");
                        io.Do_Off_Force(11);
                        io.Commit();
                        wStep = 201.91;
                    }
                    break;

                case 201.91:
                    sw.Restart();
                    wStep = 201.92;
                    break;

                case 201.92:
                    if (sw.Elapsed.TotalSeconds >= 2.0)
                    {
                        sw.Stop();
                        wStep = 202;
                    }
                    break;

                case 202: // CCW 테스트 시작
                    AppendLog($"[wStep {wStep}] CCW 테스트 시작");
                    // tmrWork는 계속 실행 (비상정지 체크를 위해)
                    wStep = 202.1;
                    NoiseCurrentTest(25, Graph[2], Graph[3], Graph[5],
                        ValStartUp[2], ValOperating[2], ValStartUp[3], ValOperating[3],
                        ValSpeed[2], Val_CCW_Resist_Min, Val_CCW_Resist_Max,
                        DecStartUp[2], DecOperating[2], DecStartUp[3], DecOperating[3],
                        DecSpeed[2], Dec_CCW_Resist, gTestID);
                    // NoiseCurrentTest 내부에서 wStep = 203으로 변경됨 (비상정지 시 wStep = 2000)
                    break;

                case 203: // 테스트 완료
                    AppendLog($"[wStep {wStep}] 테스트 완료 - 0도 검사로 이동");
                    // tmrWork는 계속 실행 중
                    wStep = 500;
                    break;

                case 500: // 0도 검사 시작
                    AppendLog($"[wStep {wStep}] 0도 검사 시작 - 게이지 전진");
                    io.Do_On_Force(10); // 게이지 전진
                    io.Commit();
                    wStep = 501;
                    break;

                case 501: // 게이지 전진 센서
                    if (io.GetInput(13)) // 게이지 전진 센서
                    {
                        AppendLog($"[wStep {wStep}] 게이지 전진 센서 확인됨 - 2초 대기 시작");
                        io.Do_Off_Force(10);
                        io.Commit();
                        sw.Restart();
                        wStep = 502;
                    }
                    break;

                case 502: // 2초 대기
                    if (sw.Elapsed.TotalSeconds >= 2.0)
                    {
                        AppendLog($"[wStep {wStep}] 2초 대기 완료 - 각도 측정 시작");
                        wStep = 503;
                    }
                    break;

                case 503: // 각도 측정 및 판정
                    double angle = ComputeTiltDeg(ValueLvdt1, ValueLvdt2, 160.0);
                    Val_Angle.Text = angle.ToString("F2");

                    // 각도 판정
                    bool angleOk = angle >= BasicAngleMin && angle <= BasicAngleMax;
                    if (angleOk)
                    {
                        Dec_Angle.Text = "OK";
                        Dec_Angle.BackColor = Color.Blue;
                        AppendLog($"[wStep {wStep}] 각도 측정: {angle:F2}° (OK, 범위: {BasicAngleMin}~{BasicAngleMax}°)");
                    }
                    else
                    {
                        Dec_Angle.Text = "NG";
                        Dec_Angle.BackColor = Color.Red;
                        AppendLog($"[wStep {wStep}] 각도 측정: {angle:F2}° (NG, 범위: {BasicAngleMin}~{BasicAngleMax}°)");
                    }

                    // 저항 판정
                    bool resistOk = ValueResist >= BasicResistMin && ValueResist <= BasicResistMax;
                    if (resistOk)
                    {
                        AppendLog($"[wStep {wStep}] 저항 측정: {ValueResist:F4}Ω (OK, 범위: {BasicResistMin}~{BasicResistMax}Ω)");
                    }
                    else
                    {
                        AppendLog($"[wStep {wStep}] 저항 측정: {ValueResist:F4}Ω (NG, 범위: {BasicResistMin}~{BasicResistMax}Ω)");
                    }

                    wStep = 504;
                    break;

                case 504: // 게이지 후진
                    AppendLog($"[wStep {wStep}] 게이지 후진 시작");
                    io.Do_On_Force(11); // 게이지 후진
                    io.Commit();
                    wStep = 505;
                    break;

                case 505: // 게이지 후진 센서
                    if (io.GetInput(14) && !_case505Executed) // 게이지 후진 센서 && 아직 실행 안 함
                    {
                        AppendLog($"[wStep {wStep}] 게이지 후진 센서 확인됨 - 최종 판정");
                        io.Do_Off_Force(11);
                        io.Commit();
                        wStep = 506;
                        _case505Executed = true;  // 실행 플래그 설정
                        AppendLog($"[wStep {wStep}] 다음 단계로 이동: wStep = 506");
                    }
                    else if (!io.GetInput(14))
                    {
                        // 센서가 false가 되면 플래그 초기화 (다음 사이클을 위해)
                        _case505Executed = false;
                    }
                    break;

                case 506: // 최종 판정 및 바코드 출력
                    // 모든 항목 OK 확인
                    bool allOk = true;
                    string ngItems = "";

                    // 0도 각도 판정
                    if (Dec_Angle.Text != "OK")
                    {
                        allOk = false;
                        ngItems += $"0도각도:{Dec_Angle.Text} ";
                    }

                    // 180도 각도 판정
                    if (Dec_Angle2.Text != "OK")
                    {
                        allOk = false;
                        ngItems += $"180도각도:{Dec_Angle2.Text} ";
                    }

                    // 스위치 각도 판정
                    if (Dec_SwitchAngle.Text != "OK")
                    {
                        allOk = false;
                        ngItems += $"스위치각도:{Dec_SwitchAngle.Text} ";
                    }

                    // CW 저항 판정
                    if (Dec_CW_Resist.Text != "OK")
                    {
                        allOk = false;
                        ngItems += $"CW저항:{Dec_CW_Resist.Text} ";
                    }

                    // CCW 저항 판정
                    if (Dec_CCW_Resist.Text != "OK")
                    {
                        allOk = false;
                        ngItems += $"CCW저항:{Dec_CCW_Resist.Text} ";
                    }

                    // CW StartUp 판정 (소음, 전류)
                    for (int i = 0; i < 2; i++)
                    {
                        if (DecStartUp[i].Text != "OK")
                        {
                            allOk = false;
                            ngItems += $"CW_StartUp[{i}]:{DecStartUp[i].Text} ";
                        }
                    }

                    // CW Operating 판정 (소음, 전류)
                    for (int i = 0; i < 2; i++)
                    {
                        if (DecOperating[i].Text != "OK")
                        {
                            allOk = false;
                            ngItems += $"CW_Operating[{i}]:{DecOperating[i].Text} ";
                        }
                    }

                    // CW 속도 판정
                    if (DecSpeed[0].Text != "OK")
                    {
                        allOk = false;
                        ngItems += $"CW_속도:{DecSpeed[0].Text} ";
                    }

                    // CCW StartUp 판정 (소음, 전류)
                    for (int i = 2; i < 4; i++)
                    {
                        if (DecStartUp[i].Text != "OK")
                        {
                            allOk = false;
                            ngItems += $"CCW_StartUp[{i}]:{DecStartUp[i].Text} ";
                        }
                    }

                    // CCW Operating 판정 (소음, 전류)
                    for (int i = 2; i < 4; i++)
                    {
                        if (DecOperating[i].Text != "OK")
                        {
                            allOk = false;
                            ngItems += $"CCW_Operating[{i}]:{DecOperating[i].Text} ";
                        }
                    }

                    // CCW 속도 판정
                    if (DecSpeed[2].Text != "OK")
                    {
                        allOk = false;
                        ngItems += $"CCW_속도:{DecSpeed[2].Text} ";
                    }

                    if (allOk)
                    {
                        if (!_barcodePrinted)  // 한 번만 출력
                        {
                            AppendLog($"[wStep {wStep}] 최종 판정: OK - 바코드 출력");
                            BarcodePrint();
                            _barcodePrinted = true;
                        }
                        wStep = 506.1;  // 다음 단계로 이동
                        AppendLog($"[wStep 506] 다음 단계로 이동: wStep = 506.1");
                    }
                    else
                    {
                        AppendLog($"[wStep {wStep}] 최종 판정: NG - {ngItems.Trim()}");
                        wStep = 506.1;  // NG여도 다음 단계로 이동
                        AppendLog($"[wStep 506] NG이지만 다음 단계로 이동: wStep = 506.1");
                    }
                    break;

                case 506.1: // 데이터베이스 저장
                    AppendLog($"[wStep {wStep}] 데이터베이스 저장 시작");
                    gSerialNo = srclbSerial.Text;  // 저장 시점에 최신 값으로 업데이트
                    InsertTableMain(
                        DateTime.Now.ToString("yyyy-MM-dd"), StartTime, DateTime.Now.ToString("yyyy-MM-dd HH:mm:ss"),
                        gPartNo, gPartName, gCarType, gSerialNo, gEndBarcode,
                        ValStartUp[0].Text, DecStartUp[0].Text, ValStartUp[1].Text, DecStartUp[1].Text,
                        ValOperating[0].Text, DecOperating[0].Text, ValOperating[1].Text, DecOperating[1].Text,
