        private bool CheckBlowerBarcodeDuplicated(string strScanData)
        {
            try
            {
                // --- DB 연결 ---
                var accdbPath = Path.Combine(AppDomain.CurrentDomain.BaseDirectory, @"DB\DataBase_Record.accdb");
                string connStr = $"Provider=Microsoft.ACE.OLEDB.12.0;Data Source={accdbPath}";
                const string TABLE = "Table_Main";

                using (var conn = new OleDbConnection(connStr))
                {
                    conn.Open();

                    string sql = $"SELECT COUNT(*) FROM [{TABLE}] WHERE [BLOWER_BARCODE] = @barcode";

                    using (var cmd = new OleDbCommand(sql, conn))
                    {
                        cmd.Parameters.AddWithValue("@barcode", strScanData);

                        int count = Convert.ToInt32(cmd.ExecuteScalar());
                        return count > 0; // 있으면 true, 없으면 false
                    }
                }
            }
            catch (Exception ex)
            {
                AppendLog($"중복 검사 오류: {ex.Message}");
                return false; // 오류 시 false (혹은 상황에 따라 true로 할 수도 있음)
            }
        }

        /// <summary>
        /// 두 LVDT 값과 간격으로 기울기(도)를 계산해 소수점 둘째 자리까지 반올림해 반환.
        /// 왼쪽이 더 높으면 +각.
        /// </summary>
        public static double ComputeTiltDeg(double lvdtLeft, double lvdtRight, double baseline)
        {
            if (!(baseline > 0.0)) throw new ArgumentOutOfRangeException(nameof(baseline), "baseline must be > 0");

            double delta = lvdtLeft - lvdtRight;
            double rad = Math.Atan2(delta, baseline);
            double deg = rad * (180.0 / Math.PI);

            // 소수점 둘째 자리 반올림 (은행가 반올림 피하기 위해 AwayFromZero)
            double rounded = Math.Round(deg, 2, MidpointRounding.AwayFromZero);
            // -0.00 방지
            if (rounded == 0) rounded = 0.0;

            return rounded;
        }

